import torch
from torchvision import models, transforms
from PIL import Image
import io
import json
import base64
from flask import Flask, request, jsonify
from werkzeug.security import safe_str_cmp

app = Flask(__name__)

# Load pre-trained model and weights
model = models.resnet50(pretrained=True)
model.eval()

def classify_image(image_bytes):
    image = Image.open(io.BytesIO(image_bytes))
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    image = transform(image)
    output = model(image.unsqueeze(0))
    _, predicted_class = torch.max(output, dim=1)
    confidence_score = torch.nn.functional.softmax(output, dim=1)[0][predicted_class].item()
    return predicted_class.item(), confidence_score

@app.route('/classify', methods=['POST'])
def classify():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    image = request.files['image']
    if not image.filename.lower().endswith(('.jpg', '.png')):
        return jsonify({'error': 'Invalid file type'}), 400

    try:
        image_bytes = image.read()
        predicted_class, confidence_score = classify_image(image_bytes)
        result = {'class': str(predicted_class), 'confidence': str(confidence_score)}
        return jsonify(result), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)